mapper.select:
select sdd.id as id, sdd.dict_sort as dictSort, sdd.dict_label as dictLabel, sdd.dict_value as dictValue, sdd.dict_type_id as dictTypeId, sdd.status as status, sdd.remark as remark, sdt.dict_name as dictName, sdd.create_by as createBy, sdd.create_time as createTime, sdd.update_by as updateBy, sdd.update_time as updateTime from sys_dict_type sdt left join sys_dict_data sdd on sdt.id = sdd.dict_type_id
and sdd.dict_type_id is not null
and sdd.status = #{status}
and sdd.dict_type_id = #{dictType}

SELECT id as id,, dict_sort as dictSort, dict_label as dictLabel, dict_value as dictValue, create_by as createBy,, create_time as createTime, update_by as updateBy, update_time as updateTime, remark, status, dict_type_id as dictTypeId, FROM sys_dict_data
AND dict_label LIKE CONCAT('%', #{query.dictLabel}, '%')
AND dict_value LIKE CONCAT('%', #{query.dictValue}, '%')
AND status = #{query.status}
AND dict_type_id = #{query.dictTypeId}
ORDER BY
${item.field} ${item.order}
ORDER BY dict_sort DESC
